import React, { useState, useRef, useEffect } from 'react';
import { Send, Plus, User, Bot, Loader2 } from 'lucide-react';
import './ChatArea.css';

function ChatArea({ conversation, messages, onSendMessage, onNewConversation, isLoading }) {
  const [input, setInput] = useState('');
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (input.trim()) {
      onSendMessage(input.trim());
      setInput('');
    }
  };

  return (
    <div className="chat-area">
      {!conversation ? (
        <div className="empty-state">
          <div className="empty-state-content">
            <Bot size={48} />
            <h2>Welcome to ChatGPT Clone</h2>
            <p>Select a conversation from the sidebar or start a new chat</p>
            <button className="start-chat-btn" onClick={onNewConversation}>
              <Plus size={20} />
              Start New Chat
            </button>
          </div>
        </div>
      ) : (
        <>
          <div className="chat-header">
            <h2>{conversation.title}</h2>
          </div>

          <div className="messages-container">
            {messages.length === 0 ? (
              <div className="empty-conversation">
                <Bot size={32} />
                <p>Start a conversation by typing a message below</p>
              </div>
            ) : (
              messages.map((message) => (
                <div
                  key={message.id}
                  className={`message ${message.role}`}
                >
                  <div className="message-avatar">
                    {message.role === 'user' ? <User size={20} /> : <Bot size={20} />}
                  </div>
                  <div className="message-content">
                    <div className="message-role">
                      {message.role === 'user' ? 'You' : 'Assistant'}
                    </div>
                    <div className="message-text">{message.content}</div>
                  </div>
                </div>
              ))
            )}
            <div ref={messagesEndRef} />
          </div>

          <form className="input-form" onSubmit={handleSubmit}>
            <div className="input-container">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Type your message..."
                className="message-input"
              />
              <button
                type="submit"
                className="send-button"
                disabled={!input.trim()}
              >
                <Send size={20} />
              </button>
            </div>
          </form>
        </>
      )}
    </div>
  );
}

export default ChatArea;
